function build_model(; N = _INLINE_DATA["N"], A = _INLINE_DATA["A"], Sf = _INLINE_DATA["Sf"], P = _INLINE_DATA["P"], D = _INLINE_DATA["D"], L = _INLINE_DATA["L"], a = _INLINE_DATA["a"], b = _INLINE_DATA["b"], c = _INLINE_DATA["c"], d = _INLINE_DATA["d"], alfa_s = _INLINE_DATA["alfa_s"], alfa_i = _INLINE_DATA["alfa_i"], QS_s = _INLINE_DATA["QS_s"], Ts = _INLINE_DATA["Ts"], RR = _INLINE_DATA["RR"], RRT = _INLINE_DATA["RRT"], delta = _INLINE_DATA["delta"], deltaT = _INLINE_DATA["deltaT"])
    model = Model()
    @variable(model, alfa[P])
    @variable(model, QS[P])
    @variable(model, QD[D])
    @variable(model, T[A])
    @variable(model, lambda[N])
    @variable(model, miu[P])
    @variable(model, teta[A])
    @variable(model, gamma[L])
    @constraint(model, r1[n in P], alfa_i[n] <= alfa[n] <= alfa_s[n])
    @constraint(model, r2[n in P], QS_s[n] - QS[n] ⟂ miu[n])
    @constraint(model, r3[n in P], alfa[n] - lambda[n] + miu[n] + b[n] * QS[n] ⟂ QS[n])
    @constraint(model, r4[n in D], lambda[n] - c[n] + d[n] * QD[n] ⟂ QD[n])
    @constraint(model, r5[(i, j) in A], Ts[i, j] - T[i, j] ⟂ teta[i, j])
    @constraint(model, r6[(i, j) in A], sum(deltaT[i, j, n] * lambda[n] for n in N) + teta[i, j] + sum(RRT[i, j, k] * gamma[k] for k in L) ⟂ T[i, j])
    @constraint(model, r7[n in N], (if n in D then QD[n] else 0) - (if n in P then QS[n] else 0) + sum(delta[n, i, j] * T[i, j] for (i, j) in A) == 0)
    @constraint(model, r8[k in L], sum(RR[k, i, j] * T[i, j] for (i, j) in A) == 0)
    @objective(model, Max, sum(c[n] * QD[n] - d[n] * QD[n] ^ 2 for n in D) - sum(a[k] * QS[k] + (b[k] / 2) * (QS[k] ^ 2) for k in Sf) - sum(teta[i, j] * Ts[i, j] for (i, j) in A) - sum(if l in Sf then 0 else(miu[l] * QS_s[l] + a[l] * QS[l] + b[l] * QS[l] ^ 2) for l in P))
    return model
end

function build_model(path::String)
    schema = JuMPConverter.AMPL.DatSchema(
        Dict{Symbol,Int}(
            :a => 1,
            :b => 1,
            :c => 1,
            :d => 1,
            :alfa_s => 1,
            :alfa_i => 1,
            :QS_s => 1,
            :Ts => 1,
            :RR => 2,
            :RRT => 2,
            :delta => 2,
            :deltaT => 2,
        ),
        [:N, :A, :Sf, :P, :D, :L],
    )
    data = if isdir(path)
        JuMPConverter.AMPL.read_csv(path, schema)
    else
        JuMPConverter.AMPL.read_dat(path, schema)
    end
    return build_model(; data...)
end
